import java.util.*;

// Generic class
class Box<T> {
    private T content;

    public void set(T content) {
        this.content = content;
    }

    public T get() {
        return content;
    }

    public boolean isEmpty() {
        return content == null;
    }
}

// Generic class with multiple type parameters
class Pair<K, V> {
    private K key;
    private V value;

    Pair(K key, V value) {
        this.key = key;
        this.value = value;
    }

    public K getKey() { return key; }
    public V getValue() { return value; }

    @Override
    public String toString() {
        return "Pair{" + key + "=" + value + "}";
    }
}

// Generic method
class Utility {
    // Generic method with type parameter
    public static <T> void printArray(T[] array) {
        for (T element : array) {
            System.out.print(element + " ");
        }
        System.out.println();
    }

    // Generic method with wildcard
    public static void printList(List<?> list) {
        for (Object item : list) {
            System.out.print(item + " ");
        }
        System.out.println();
    }

    // Bounded wildcard
    public static double sumOfNumbers(List<? extends Number> list) {
        double sum = 0;
        for (Number n : list) {
            sum += n.doubleValue();
        }
        return sum;
    }
}

public class GenericsExample {
    public static void main(String[] args) {
        // Generic class with different types
        System.out.println("=== Box Class ===");
        Box<String> stringBox = new Box<>();
        stringBox.set("Hello");
        System.out.println("String box: " + stringBox.get());

        Box<Integer> intBox = new Box<>();
        intBox.set(42);
        System.out.println("Integer box: " + intBox.get());

        Box<Double> doubleBox = new Box<>();
        doubleBox.set(3.14);
        System.out.println("Double box: " + doubleBox.get());

        // Pair with different types
        System.out.println("=== Pair Class ===");
        Pair<String, Integer> pair1 = new Pair<>("Age", 25);
        Pair<Integer, String> pair2 = new Pair<>(1, "One");
        System.out.println("Pair1: " + pair1);
        System.out.println("Pair2: " + pair2);

        // Generic methods
        System.out.println("=== Generic Methods ===");
        String[] words = {"Java", "Generics", "Are", "Great"};
        Integer[] numbers = {1, 2, 3, 4, 5};

        Utility.printArray(words);
        Utility.printArray(numbers);

        // Wildcard methods
        System.out.println("=== Wildcards ===");
        List<String> stringList = Arrays.asList("A", "B", "C");
        List<Integer> intList = Arrays.asList(10, 20, 30);

        Utility.printList(stringList);
        Utility.printList(intList);

        // Bounded wildcard
        System.out.println("=== Bounded Wildcards ===");
        List<Integer> ints = Arrays.asList(1, 2, 3, 4, 5);
        List<Double> doubles = Arrays.asList(1.5, 2.5, 3.5);
        List<String> strings = Arrays.asList("A", "B");

        System.out.println("Sum of ints: " + Utility.sumOfNumbers(ints));
        System.out.println("Sum of doubles: " + Utility.sumOfNumbers(doubles));
        // Utility.sumOfNumbers(strings); // ERROR! String not a Number

        // Type safety
        System.out.println("=== Type Safety ===");
        // Without generics: risk of ClassCastException
        // With generics: compile-time checking

        // Collections without generics (bad)
        @SuppressWarnings("rawtypes")
        ArrayList rawList = new ArrayList();
        rawList.add("Hello");
        rawList.add(42);  // No error
        // String s = (String) rawList.get(1); // ClassCastException!

        // Collections with generics (good)
        ArrayList<String> safeList = new ArrayList<>();
        safeList.add("Hello");
        // safeList.add(42); // Compiler error!
        String s = safeList.get(0);  // Safe, no cast needed
        System.out.println("Safe list: " + safeList);
    }
}

