class Container<T> {
    private T item;

    Container(T item) {
        this.item = item;
    }

    public T get() {
        return item;
    }

    public void set(T item) {
        this.item = item;
    }

    public boolean isSame(Container<T> other) {
        return item.equals(other.item);
    }
}

public class GenericsPractice {
    public static void main(String[] args) {
        Container<String> c1 = new Container<>("Hello");
        Container<Integer> c2 = new Container<>(42);
        Container<String> c3 = new Container<>("Hello");

        System.out.println("c1: " + c1.get());
        System.out.println("c2: " + c2.get());
        System.out.println("c3: " + c3.get());
        System.out.println("c1 and c3 are same: " + c1.isSame(c3));
        // c1.isSame(c2); // Compiler error! Different types
    }
}
